import React from 'react';

export default function Events() {
  return (
    <div className="auth-container">
      <h2>Upcoming College Events</h2>
      <img
        src="/events.jpg"
        alt="Events"
        style={{ maxWidth: '100%', borderRadius: '8px' }}
      />
      <p>Stay tuned for the latest college fests, workshops, and live updates.</p>
      <a href="https://www.gla.ac.in/events" target="_blank" rel="noreferrer">
        <button>See Events</button>
      </a>
    </div>
  );
}
